class Solution {
    public int minMovesToMakePalindrome(String s) {
        int n = s.length();
        int moves = 0;
        for (int i = 0, j = n - 1; i < j; i++, j--) {
            if (s.charAt(i) != s.charAt(j)) {
                moves++;
            }
        }
        return moves;
    }
}
